def sumofEvenFactors(n):
    total = 0
    for i in range(1, int(n**0.5) + 1):
        if n % i == 0:
            if i % 2 == 0:
                total += i
            if (n // i) % 2 == 0 and i != n // i:
                total += (n // i)
    return total

# Test cases
assert sumofEvenFactors(18) == 26
assert sumofEvenFactors(30) == 48
assert sumofEvenFactors(6) == 8
